class Solution:
    def getMinSwaps(self, num: str, k: int) -> int:
        from itertools import permutations
        n = len(num)
        count = 0
        for i in range(n):
            for j in range(i + 1, n):
                temp = list(num)
                temp[i], temp[j] = temp[j], temp[i]
                new_num = "".join(temp)
                if int(new_num) > int(num):
                    count += 1
        return count
